### Extend ElementNode: Create Custom Paragraph

Source: https://github.com/facebook/lexical/blob/main/packages/lexical-website/docs/concepts/nodes.mdx

Demonstrates extending Lexical's ElementNode to create a custom paragraph node. Includes static methods for node type and cloning, as well as methods for DOM element creation and updating.

```typescript
import {ElementNode, LexicalNode} from 'lexical';

export class CustomParagraph extends ElementNode {
  static getType(): string {
    return 'custom-paragraph';
  }

  static clone(node: CustomParagraph): CustomParagraph {
    return new CustomParagraph(node.__key);
  }

  createDOM(): HTMLElement {
    // Define the DOM element here
    const dom = document.createElement('p');
    return dom;
  }

  updateDOM(prevNode: this, dom: HTMLElement, config: EditorConfig): boolean {
    // Returning false tells Lexical that this node does not need its
    // DOM element replacing with a new copy from createDOM.
    return false;
  }
}
```

