### Extend TextNode using legacy static methods

Source: https://github.com/facebook/lexical/blob/main/packages/lexical-website/docs/concepts/nodes.mdx

This code snippet demonstrates extending the Lexical TextNode using legacy static methods and properties. It defines a 'color' property, handles JSON import/export, and updates the DOM based on color changes. This approach is shown for compatibility but the $config method is preferred. It requires the 'lexical' package.

```typescript
import {
  $applyNodeReplacement,
  type EditorConfig,
  type LexicalNode,
  type SerializedTextNode,
  type Spread,
  TextNode,
} from 'lexical';

const DEFAULT_COLOR = 'inherit';

export type SerializedColoredNode = Spread<{
  color?: string;
}, SerializedTextNode>;

export class ColoredNode extends TextNode {
  __color: string;

  constructor(
    text: string = '',
    color: string = DEFAULT_COLOR,
    key?: NodeKey,
  ): void {
    super(text, key);
    this.__color = color;
  }

  static getType(): string {
    return 'colored';
  }

  static clone(node: ColoredNode): ColoredNode {
    return new ColoredNode(node.__text, node.__color, node.__key);
  }

  static importFromJSON(serializedNode: SerializedColoredNode) {
    return new ColoredNode().updateFromJSON(serializedNode);
  }

  updateFromJSON(serializedNode: SerializedColoredNode) {
    const self = super.updateFromJSON(serializedNode);
    self.__color =
      typeof serializedNode.color === 'string'
        ? serializedNode.color
        : DEFAULT_COLOR;
    return self;
  }

  exportJSON(): SerializedColoredNode {
    return {
      ...super.exportJSON(),
      color: this.__color === DEFAULT_COLOR ? undefined : this.__color,
    };
  }

  createDOM(config: EditorConfig): HTMLElement {
    const element = super.createDOM(config);
    element.style.color = this.__color;
    return element;
  }

  updateDOM(prevNode: this, dom: HTMLElement, config: EditorConfig): boolean {
    if (super.updateDOM(prevNode, dom, config)) {
      return true;
    }
    if (prevNode.__color !== this.__color) {
      dom.style.color = this.__color;
    }
    return false;
  }
}

export function $createColoredNode(text: string, color: string): ColoredNode {
  return $applyNodeReplacement(new ColoredNode(text, color));
}

export function $isColoredNode(
  node: LexicalNode | null | undefined,
): node is ColoredNode {
  return node instanceof ColoredNode;
}
```

