### Extend ElementNode using $config in TypeScript

Source: https://github.com/facebook/lexical/blob/main/packages/lexical-website/docs/concepts/nodes.mdx

Demonstrates extending Lexical's ElementNode with the $config method. This approach simplifies node creation by allowing configuration directly within the class. It requires Lexical core types and defines custom DOM creation and update logic.

```typescript
import {
  $create,
  type EditorConfig,
  ElementNode,
  type LexicalNode,
} from 'lexical';

export class CustomParagraph extends ElementNode {
  // highlight-start
  $config() {
    return this.config('custom-paragraph', {extends: ElementNode});
  }
  // highlight-end

  createDOM(): HTMLElement {
    // Define the DOM element here
    const dom = document.createElement('p');
    return dom;
  }

  updateDOM(prevNode: this, dom: HTMLElement, config: EditorConfig): boolean {
    // Returning false tells Lexical that this node does not need its
    // DOM element replaced with a new one from createDOM.
    return false;
  }
}
```
